import{_ as i,o as l,c as t,a2 as e}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F13: 資本支出效能與股利防禦 - 投資研究員審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/8064_東捷/20260429/F13_資本支出效能與股利防禦_投資研究員.md","filePath":"審計報告庫/財務審計/8064_東捷/20260429/F13_資本支出效能與股利防禦_投資研究員.md"}'),r={name:"審計報告庫/財務審計/8064_東捷/20260429/F13_資本支出效能與股利防禦_投資研究員.md"};function o(n,a,s,h,d,_){return l(),t("div",null,[...a[0]||(a[0]=[e('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f13-資本支出效能與股利防禦-投資研究員審計報告" tabindex="-1">F13: 資本支出效能與股利防禦 - 投資研究員審計報告 <a class="header-anchor" href="#f13-資本支出效能與股利防禦-投資研究員審計報告" aria-label="Permalink to &quot;F13: 資本支出效能與股利防禦 - 投資研究員審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>資本支出 (CapEx) 的投入效能為何？自由現金流 (FCF) 是否足以支撐其股利政策？是否存在「借債配息」之虛耗現象？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>CapEx/營收&lt;1.2%屬輕資產型，擴產動能有限；FCF 改善至 6.17 億，股息覆蓋 6.2x。惟 2022 年負 CFO 仍配 2.06 億屬動用儲備配息。綜合判定：投資效能偏低無害，股利已轉穩健。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>診斷評級：B (持平→改善中)</strong></li><li><strong>重點數據</strong>： <ul><li>2022→2025 CapEx/營收：0.52%→1.14%（仍極低）</li><li>FCF 覆蓋股息：2023 年 0.91x → 2025 年 6.24x</li><li>負債比率：52.9% → 38%（去槓桿明確）</li><li>3 年總 CapEx 5,669 萬，不及 2025 年 FCF 的 10%</li></ul></li><li><strong>診斷見解</strong>：輕資產設備商，CapEx 投入極小。2024 年加碼至 3,044 萬後營收回升 10.2%，顯邊際改善。2022 年負 CFO 強配 2.06 億係動用現金儲備（期末 21.34 億），非舉債配息。此後降息 $1.5→$0.6，管理層已自律調整。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="資本支出效能實測" tabindex="-1">資本支出效能實測 <a class="header-anchor" href="#資本支出效能實測" aria-label="Permalink to &quot;資本支出效能實測&quot;">​</a></h3><ul><li><strong>核心重點</strong>：近 3 年 CapEx 與次年營收連動（TWD 千元）：2022 CapEx 20,199→2023 營收 2,990,451(-23.7%，面板反轉)；2023 CapEx 6,054→2024 營收 2,603,886(-12.9%)；2024 CapEx 30,435→2025 營收 2,870,684(+10.2%，回報係數 8.76x)</li><li><strong>深度見解</strong>：CapEx/營收僅 0.2%~1.2%，屬維護型投入。2024 年加碼攻半導體先進封裝，2025 年營收反彈驗證方向。但整體規模小，不具翻轉營收量級動能。</li></ul><h3 id="配息含金量審核" tabindex="-1">配息含金量審核 <a class="header-anchor" href="#配息含金量審核" aria-label="Permalink to &quot;配息含金量審核&quot;">​</a></h3><ul><li><strong>核心重點</strong>：FCF 覆蓋股息：2023 年 0.91x(缺口 2,251 萬)、2024 年 5.64x、2025 年 6.24x</li><li><strong>深度見解</strong>：2023 年缺口經年報勾稽：帳上現金 20.53 億，缺口僅佔 1.1%，動用儲備而非舉債。此後公司降息 $1.5→$0.7→$0.6，負債比同步從 52.9% 降至 38%，確無借債配息。</li></ul><h3 id="股利穩定性測試" tabindex="-1">股利穩定性測試 <a class="header-anchor" href="#股利穩定性測試" aria-label="Permalink to &quot;股利穩定性測試&quot;">​</a></h3><ul><li><strong>核心重點</strong>：壓力測試(淨利-20%)：114 年淨利 2.25 億→壓力 1.80 億；擬議股息 1.81 億→Payout 100.8%。但 FCF 6.17 億→壓力 FCF 4.94 億，覆蓋 2.72x</li><li><strong>深度見解</strong>：以淨利論，壓力下全數盈餘配息，無保留盈餘。但 FCF 覆蓋充裕，安全邊際來自 CFO 轉正(-0.92→6.5 億)與輕資產高 FCF 轉換率。防禦韌性：中偏高。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一（擴產效益虛高）</strong>：2024 年 CapEx 增幅 402.7%（6,054→30,435），對應 2025 年營收增幅 10.2%，回報係數 8.76x 看似優異，但 2024 年營收是 3 年新低（26.04 億），基期偏低扭曲放大倍數。若以 2025 年營收 28.71 億對比 2022 年高點 39.21 億，3 年仍衰退 26.8%。CapEx 加碼未能將營收推回歷史高峰，半導體轉型仍在初期，量產貢獻不足。</li><li><strong>空頭風險二（股息回復過快）</strong>：114 年擬議股息 $1.1 為前一年 $0.6 的 183% 增幅，新股利政策 Payout 80.7%，將獲利多數還給股東。若 2026 年半導體設備出貨延遲或 FOPLP 擴產不如預期（群創產能建置不確定性），淨利恐再度下滑，屆時 80%+ 的 Payout 將導致保留盈餘匱乏，缺乏自體擴張資金。對策：公司應維持 50-60% Payout Ratio，保留資金用於半導體設備研發。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>年報/財報</strong>: OK <ul><li>2025 Q4 合併財報（114 vs 113 年度）：Revenue、CapEx、CFO、股利附註（p.9, p.13, p.46）</li><li>2024 Q4 合併財報（113 vs 112 年度）：歷史比較數據（p.8-13, p.48）</li><li>2023 Q4 合併財報（112 vs 111 年度）：111 年負 CFO 與高額股利驗證（p.8-13, p.47）</li></ul></li><li><strong>關鍵核對碼</strong>: <ul><li>2025 CapEx = 32,695 千元（現金流量表「取得不動產、廠房及設備」）</li><li>2025 CFO = 650,033 千元 → FCF = 617,338</li><li>Dividends paid 2025 = 98,891 千元（113 年盈餘配 $0.6，籌資活動）</li><li>Proposed 114 年現金股利 = 181,300 千元（$1.1/股，附註揭露）</li><li>負債比連續 4 年下降：52.9%→48.2%→42.9%→38%</li></ul></li><li><strong>FinMind</strong>: 無法調用（無 API 憑證），數據以年報現金流量表直接摘錄取代。</li><li><strong>yfinance</strong>: 404 error（8064.TW 未收錄），無法作為輔助驗證。</li><li><strong>網路校準</strong>: 優分析/CMoney 報導確認東捷先進封裝轉型方向與財務趨勢一致。</li></ul>',19)])])}const p=i(r,[["render",o]]);export{u as __pageData,p as default};
